function formatInternationalPhone(phone, locationHint) {
  if (!phone || phone === 'undefined' || phone === 'null') return '';

  // Remove all non-digit characters except +
  let cleaned = phone.toString().replace(/[^\d+]/g, '');

  // If already has +, assume it's properly formatted
  if (cleaned.startsWith('+')) {
    // Validate E.164 format (max 15 digits after +)
    const digitsOnly = cleaned.replace(/\D/g, '');
    if (digitsOnly.length >= 8 && digitsOnly.length <= 15) {
      return cleaned;
    }
    return '';
  }

  // Remove leading zeros
  cleaned = cleaned.replace(/^0+/, '');

  // Check if it starts with a country code already (no +)
  const commonPrefixes = ['1', '44', '61', '49', '33', '91', '86', '81', '55', '52', '39', '34', '7', '380', '48', '31', '32', '41', '46'];
  let hasCountryCode = false;
  let detectedCountry = '';

  for (const prefix of commonPrefixes) {
    if (cleaned.startsWith(prefix) && cleaned.length > prefix.length + 6) {
      hasCountryCode = true;
      break;
    }
  }

  // Try to detect country from location hint
  let countryCode = '';
  if (locationHint) {
    const hint = locationHint.toString().toLowerCase();
    for (const [key, code] of Object.entries(countryHints)) {
      if (hint.includes(key)) {
        countryCode = code;
        break;
      }
    }
  }

  // Format logic
  if (cleaned.startsWith('00')) {
    // International format with 00 prefix
    return '+' + cleaned.substring(2);
  } else if (hasCountryCode && !countryCode) {
    // Has country code but no hint, add + and assume valid
    return '+' + cleaned;
  } else if (countryCode && !cleaned.startsWith(countryCode.replace('+', ''))) {
    // Add detected country code
    return countryCode + cleaned;
  } else if (cleaned.length >= 10 && cleaned.length <= 15) {
    // Assume it needs + (if no country detected, default behavior)
    if (countryCode) return countryCode + cleaned;
    // If no country hint and looks like local number, try to guess or return as is
    return '+' + cleaned;
  }

  return '';
}

for (const item of items) {
  const json = item.json;

  // Extract fields with flexible naming
  const company = json['Company Name'] || json['Company'] || json['company'] || json['Business'] || json['Name'] || '';
  const location = json['Location'] || json['location'] || json['City'] || json['city'] || json['Country'] || json['Address'] || json['Region'] || '';
  let phone = json['Phone'] || json['phone'] || json['Mobile'] || json['mobile'] || json['Cell'] || json['Telephone'] || json['Contact'] || '';
  const rating = parseFloat(json['Rating'] || json['rating'] || json['Stars'] || json['Review'] || 0);
  const email = json['Email'] || json['email'] || json['E-mail'] || json['Mail'] || '';
  const website = json['Website'] || json['website'] || json['URL'] || json['url'] || json['Web'] || json['Site'] || '';

  // Format phone internationally
  const formattedPhone = formatInternationalPhone(phone, location);

  // Validate email
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const hasValidEmail = email && emailRegex.test(email.toString());

  // Detect country for AI context
  let detectedCountry = 'International';
  if (location) {
    const loc = location.toLowerCase();
    for (const [key, code] of Object.entries(countryHints)) {
      if (loc.includes(key)) {
        detectedCountry = key.charAt(0).toUpperCase() + key.slice(1);
        break;
      }
    }
  }

  // E.164 validation check
  const isValidE164 = formattedPhone.match(/^\+[1-9]\d{6,14}$/);

  cleaned.push({
    json: {
      companyName: company,
      location: location,
      phone: formattedPhone,
      originalPhone: phone,
      rating: rating,
      email: hasValidEmail ? email : '',
      website: website,
      hasWebsite: website && website.toString().length > 3 && website.toString().includes('.'),
      hasEmail: hasValidEmail,
      hasPhone: isValidE164 !== null,
      country: detectedCountry,
      qualificationScore: (hasValidEmail ? 1 : 0) + (isValidE164 ? 1 : 0) + (rating >= 3.5 ? 1 : 0)
    }
  });
}

return cleaned;

// Select voice based on country
