const location = ($input.first().json.location || '').toLowerCase();

let voice = 'Polly.Joanna'; // Default US
let language = 'en-US';
let accent = 'American';

if (country.includes('uk') || country.includes('britain') || location.includes('london')) {
  voice = 'Polly.Emma';
  language = 'en-GB';
  accent = 'British';
} else if (country.includes('australia') || location.includes('sydney') || location.includes('melbourne')) {
