const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // ── Phone Formatting ──
  let phone = (data.Phone || '').toString().trim().replace(/[\s\-().]/g, '');
  let country = 'UNKNOWN';
  let hasPhone = false;

  const countryMap = [
    { prefix: '+1',   codes: ['1'],   name: 'USA/Canada',    keywords: ['usa','united states','canada','us,','ca,'] },
    { prefix: '+44',  codes: ['44'],  name: 'UK',            keywords: ['uk','united kingdom','england','britain'] },
    { prefix: '+91',  codes: ['91'],  name: 'India',         keywords: ['india','mumbai','delhi','bangalore','chennai','hyderabad','pune','kolkata'] },
    { prefix: '+61',  codes: ['61'],  name: 'Australia',     keywords: ['australia','sydney','melbourne','brisbane'] },
    { prefix: '+49',  codes: ['49'],  name: 'Germany',       keywords: ['germany','berlin','munich','hamburg'] },
    { prefix: '+33',  codes: ['33'],  name: 'France',        keywords: ['france','paris','lyon','marseille'] },
    { prefix: '+971', codes: ['971'], name: 'UAE',           keywords: ['uae','dubai','abu dhabi','sharjah'] },
    { prefix: '+65',  codes: ['65'],  name: 'Singapore',     keywords: ['singapore'] },
    { prefix: '+1',   codes: ['1'],   name: 'USA',           keywords: [] }
  ];

  const locationLower = (data.Location || '').toLowerCase();
  let detectedCountry = countryMap.find(c => c.keywords.some(k => locationLower.includes(k)));
  if (!detectedCountry) detectedCountry = { prefix: '+1', name: 'USA', codes: ['1'] };
  country = detectedCountry.name;

  if (phone) {
    if (!phone.startsWith('+')) {
      // Strip leading 0 if present
      const stripped = phone.replace(/^0+/, '');
      phone = detectedCountry.prefix + stripped;
    }
    // Basic E.164 validation: starts with + and 7-15 digits
    hasPhone = /^\+[1-9]\d{6,14}$/.test(phone);
    if (!hasPhone) phone = '';
  }

  // ── Email Validation ──
  const email = (data.Email || '').trim().toLowerCase();
  const hasEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  // ── Website Check ──
  const website = (data.Website || '').trim();
  const hasWebsite = website.length > 0 && website !== 'N/A' && website !== '-';

  // ── Rating ──
  const rating = parseFloat(data.Rating) || 0;

  // ── Qualification Score ──
  let score = 0;
  if (hasEmail) score += 30;
  if (hasPhone) score += 30;
  if (rating >= 4.5) score += 40;
  else if (rating >= 4.0) score += 30;
  else if (rating >= 3.5) score += 20;
  else if (rating > 3.0) score += 10;

  const priority = score >= 70 ? 'High' : 'Medium';

  results.push({
    json: {
      companyName:  data['Company Name'] || data.companyName || '',
      location:     data.Location || '',
      phone:        hasPhone ? phone : '',
      email:        hasEmail ? email : '',
      rating,
      website,
      country,
      hasEmail,
      hasPhone,
      hasWebsite,
      score,
      priority
    }
  });
}

return results;

const item = $input.first();
const raw = item.json.message?.content || item.json.choices?.[0]?.message?.content || '';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  // Fallback: extract from partial JSON
  const subjectMatch = raw.match(/"subject"\s*:\s*"([^"]+)"/);
  const bodyMatch = raw.match(/"body"\s*:\s*"([^"]+)"/);
  parsed = {
    subject: subjectMatch ? subjectMatch[1] : 'Quick question about your business',
    body: bodyMatch ? bodyMatch[1] : raw
  };
}

// Merge back with original lead data
const lead = $('NODE 6: Has Email?').first().json;
return [{ json: { ...lead, emailSubject: parsed.subject, emailBody: parsed.body } }];

const item = $input.first();
const raw = item.json.message?.content || item.json.choices?.[0]?.message?.content || '';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  parsed = { full_script: raw, greeting: '', pitch: '', cta: '' };
}

const lead = $('NODE 10: Has Phone?').first().json;

// Voice mapping by country
const voiceMap = {
  'USA':         'Polly.Joanna',
  'USA/Canada':  'Polly.Joanna',
  'UK':          'Polly.Emma',
  'India':       'Polly.Aditi',
  'Australia':   'Polly.Nicole',
  'Germany':     'Polly.Marlene',
  'France':      'Polly.Celine',
  'UAE':         'Polly.Zeina',
  'Singapore':   'Polly.Joanna'
};
const voice = voiceMap[lead.country] || 'Polly.Joanna';

return [{
  json: {
    ...lead,
    callScript: parsed.full_script,
    callGreeting: parsed.greeting,
    callPitch: parsed.pitch,
    callCTA: parsed.cta,
    objectionHandlers: parsed.objection_handlers || {},
    twilioVoice: voice
  }
}];

// This node just passes through to loop back to SplitInBatches
// n8n handles the loop automatically when SplitInBatches has more items
return $input.all();
